form:Form.form:Scripts:
		function Guardar()
{  	
 	Ctrl('legajos').DelAllRow();
 	for (key in arrA)
 	{ 
 		var rowLeg = Ctrl('legajos').AddRow();
 		rowLeg.SetAttr('id', key.substr(1));
 		rowLeg.SetAttr('persona', arrA[key].associatedELE.getAttribute("e_numero_legajo") + " - " + arrA[key].associatedELE.getAttribute("d_ape_y_nom"));
 	}

	Ctrl("main").DoEvent("SAVE");
}

qry:select.qry:xquery:
			for $r in sql('
	SELECT EMP.d_empresa, LEG.oi_personal_emp, LEG.e_numero_legajo, PER.d_ape_y_nom, SEC.policy
	FROM 
	PER01_PERSONAL as PER, 
	PER02_PERSONAL_EMP as LEG, 
	ORG03_EMPRESAS as EMP,
	NMD_SECURITY(class=\'NucleusRH.Base.Personal.LegajoEmpresa.PERSONAL_EMP\') as SEC
	JOIN 
	PER.oi_personal INNER LEG.oi_personal,
	LEG.oi_empresa INNER EMP.oi_empresa,
	LEG.oi_personal_emp LEFT OUTER SEC.id
	WHERE 1=1 
	{%?('##activos##'='1') {% and LEG.oi_indic_activo= \'1\' %} {% %} %}
	{%?('##empresa##'!='') {% and LEG.oi_empresa = ##empresa## %} {% %} %}			
	{%?('##f_ingreso_hasta##'!='') {% and LEG.f_ingreso <= STRING2DATE(##f_ingreso_hasta##) %} {% %} %}
	{%?('##leg_desde1##'!='' AND '##leg_hasta1##'!='') 
		{% and (LEG.e_numero_legajo >= ##leg_desde1## AND LEG.e_numero_legajo <= ##leg_hasta1## %} 
		{% %} 
	%}
	{%?('##leg_desde2##'!='' AND '##leg_hasta2##'!='') 
		{% or LEG.e_numero_legajo >= ##leg_desde2## AND LEG.e_numero_legajo <= ##leg_hasta2## %} 
		{% %} 
	%}
	{%?('##leg_desde3##'!='' AND '##leg_hasta3##'!='') 
		{% or LEG.e_numero_legajo >= ##leg_desde3## AND LEG.e_numero_legajo <= ##leg_hasta3## %} 
		{% %} 
	%}
	{%?('##leg_desde1##'!='' OR '##leg_hasta1##'!='' OR '##leg_desde2##'!='' OR '##leg_hasta2##'!='' OR '##leg_desde3##'!='' OR '##leg_hasta3##'!='') 									
		{% ) %} 
		{%	{%?('##leg_list##'!='') 
					{% AND 1 = 2%}
					{% %}
				%}
		%}
	%}
	{%?('##indic_activo##'!='') {% and LEG.oi_indic_activo = ##indic_activo## %} {% %} %}
	{%?('##egresado##'='1') {% and isnotnull(LEG.f_egreso) %} {% %} %}
	{%?('##egresado##'='0') {% and isnull(LEG.f_egreso) %} {% %} %}
	{%?('##tipo_per##'!='') {% and LEG.oi_tipo_personal = ##tipo_per## %} {% %} %}
	{%?('##forma_pago##'!='') {% and LEG.oi_forma_pago = ##forma_pago## %} {% %} %}			
	{%?('##leg_list##'!='') 
		{%

		UNION SELECT 
			EMP.d_empresa, 
			LEG.oi_personal_emp, 
			LEG.e_numero_legajo, 
			PER.d_ape_y_nom, 
			SEC.policy
		FROM 
			PER01_PERSONAL as PER, 
			PER02_PERSONAL_EMP as LEG, 
			ORG03_EMPRESAS as EMP,
			NMD_SECURITY(class=\'NucleusRH.Base.Personal.LegajoEmpresa.PERSONAL_EMP\') as SEC
		JOIN 
			PER.oi_personal INNER LEG.oi_personal,
			LEG.oi_empresa INNER EMP.oi_empresa,
			LEG.oi_personal_emp LEFT OUTER SEC.id
		WHERE 
			1=1 
			{%?('##activos##'='1') {% and LEG.oi_indic_activo= \'1\' %} {% %} %}
			{%?('##empresa##'!='') {% and LEG.oi_empresa = ##empresa## %} {% %} %}			
			{%?('##indic_activo##'!='') {% and LEG.oi_indic_activo = ##indic_activo## %} {% %} %}
			{%?('##egresado##'='1') {% and isnotnull(LEG.f_egreso) %} {% %} %}
			{%?('##egresado##'='0') {% and isnull(LEG.f_egreso) %} {% %} %}
			{%?('##tipo_per##'!='') {% and LEG.oi_tipo_personal = ##tipo_per## %} {% %} %}
			{%?('##forma_pago##'!='') {% and LEG.oi_forma_pago = ##forma_pago## %} {% %} %}						
			AND LEG.e_numero_legajo in (##leg_list##) 
			%} 
			{% %} 
	%}
	ORDER BY d_empresa ASC, e_numero_legajo ASC
')/ROWS/ROW
